import theme from '@/theme/theme';
import React from 'react';
import styled from 'styled-components';
import Button from '../ui/Button';

const HeroContainer = styled.div `
  height: 100vh;
  background-image: url('/Images/Bg.png');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-top: -80px;
  padding-top: 80px;
`;

const TextWrap = styled.h1 `
  display: flex;
  align-items: center;
  flex-direction: column;
`;

const Title = styled.h1 `
  font-size: 4.125rem;
  font-family: 'Rightgrotesk-widemedium', sans-serif;
  font-weight: 500;
  line-height: 120%;
  color: ${
    theme.colors.secondary
};
margin-bottom: 3rem;

  span {
    color: ${
    theme.colors.primary
};
  }
`;

const SubTitle = styled.p `
  font-family: 'Pangram-Regular', sans-serif;
  font-weight: 400;
  font-size: 16px;
  line-height: 150%;
  letter-spacing: 0%;
  text-align: center;
  color: ${
    theme.colors.secondaryTextColor
};
margin-bottom: 3rem;

`;

const HeroPage = () => {
    return (
        <HeroContainer>
            <TextWrap>

                <Title>From Beginner to Confident<br/>{' '}
                    <span>
                        UI/UX Designer
                    </span>
                    {' '}
                    in 8 Weeks</Title>
                <SubTitle>No fluff. Just practical skills, real projects, and AI-powered tools to help you break into the design industry.</SubTitle>
                <Button text="Book My Free Career Call"
                    bgColor={
                        theme.colors.primary
                    }
                    textColor={
                        theme.colors.secondary
                    }
                    iconSrc="/Logo/whatsappLogo.svg"
                    iconAlt="WhatsApp"
                    
                    width='19.063rem'/>
            </TextWrap>
        </HeroContainer>
    );
};

export default HeroPage;
